+function resolveEnvCookieSource(warnings: string[]): CookieSource[] | undefined {
+  for (const key of ENV_COOKIE_SOURCE_KEYS) {
+    const value = normalizeValue(process.env[key])
+    if (value) {
+      return parseCookieSourceList(value, warnings)
+    }
+  }
